INSERT INTO `preguntas` (`id`, `enunciado`, `correcta`, `falsa1`, `falsa2`, `falsa3`, `estado`) VALUES
(3, 'Mencione el patrono de Unicatólica:', 'San José', 'San Francisco de Asís', 'San Francisco Javier', 'San Antonio', 1),
(4, 'La cruz de oro en la bandera de Unicatólica Representa:', 'Jesucristo como la luz de las naciones', 'El oro sacado de sur América', 'Símbolo de las cruzadas ', 'La cruz de cristo', 1),
(5, 'Las cuatro estrellas fulgentes en la bandera, emblema de Unicatólica, representan:', 'Los cuatro puntos cardinales', 'El cuatro como número par', 'Los cuatro jinetes del apocalipsis', 'Los cuatro valores Institucionales', 1),
(6, 'Señale cual es la misión correcta de la Unicatólica:', 'La Fundación Universitaria Católica Lumen Gentium – UNICATÓLICA, comprometida con los valores cristianos, forma personas de manera integral, reafirmando su dignidad humana en la relación con Dios, consigo mismo, con los demás y con el medio ambiente, a través de la generación y difusión del conocimiento, para contribuir al desarrollo de los pueblos.', 'La Fundación Universitaria Católica Lumen Gentium – UNICATÓLICA, comprometida con los valores, forma personas de manera integral, reafirmando su dignidad humana en la relación con Dios, consigo mismo, con los demás y con el medio ambiente, a través de la generación y difusión del conocimiento, para contribuir al desarrollo de los pueblos.', 'La Fundación Universitaria Católica Lumen Gentium – UNICATÓLICA, comprometida con los valores ignacianos, forma personas de manera integral, reafirmando su dignidad humana en la relación con Dios, consigo mismo, con los demás y con el medio ambiente, a través de la generación y difusión del conocimiento, para contribuir al desarrollo de los pueblos.', 'La Fundación Universitaria Católica Lumen Gentium – UNICATÓLICA, comprometida con los valores cristianos, forma personas de manera integral, confirmando su dignidad humana en la relación con Dios, consigo mismo, con los demás y con el medio ambiente, a través de la generación y difusión del conocimiento, para contribuir al desarrollo de los pueblos.', 1),
(7, 'Señale cual es la visión correcta de Unicatólica:', 'La Fundación Universitaria Católica Lumen Gentium – UNICATÓLICA – Institución de la Arquidiócesis de Cali, será reconocida por su carácter socialmente incluyente, por la pertinencia y calidad de sus programas y proyectos institucionales, la vocación hacia el servicio social de sus egresados y por la defensa de la dignidad humana y de la paz.', 'La Fundación Universitaria Católica Lumen Gentium – UNICATÓLICA – Institución de la Arquidiócesis de Colombia, será reconocida por su carácter socialmente incluyente, por la pertinencia y calidad de sus programas y proyectos institucionales, la vocación hacia el servicio social de sus egresados y por la defensa de la dignidad humana y de la paz.', 'La Fundación Universitaria Católica Lumen Gentium – UNICATÓLICA – Institución de la Arquidiócesis de Colombia, será reconocida por su carácter, por la pertinencia y calidad de sus programas y proyectos institucionales, la vocación hacia el servicio social de sus egresados y por la defensa de la dignidad humana y de la paz.', 'La Fundación Universitaria Católica Lumen Gentium – UNICATÓLICA – Institución de la Arquidiócesis de Cali, será reconocida por su carácter socialmente incluyente, por la pertinencia y calidad de sus programas sus instalaciones, la vocación hacia el servicio social de sus egresados y por la defensa de la dignidad humana y de la paz.', 1),
(8, 'Cuál es el principio de Unicatólica que No coincide con la definición: ', 'Libertad de Pensamiento y Actitud Crítica: se respetan las distintas ideas, opiniones, creencias y posturas, sin importar de donde vengan o el sentido que tengan, incluso si no tienen sentido ni coherencia.', 'Respeto por la Dignidad Humana: se reconoce a la persona como sujeto con valor en sí mismo y con derechos intrínsecos e inalienables derivados de su condición humana.', 'Vivencia de la Identidad Cristiana-Eclesial: se reconoce la identidad centrada en la formación de seres humanos capaces de realizarse plena e integralmente en su dimensión relacional: consigo mismo, con los demás, con el entorno y con el trascendente.', 'Cuidado de la Casa Común: se reconoce el compromiso de actuar y responder con integridad y respeto en la totalidad de las relaciones e interacciones con los sistemas naturales y sociales, en función de la promoción de la calidad de vida y la solidaridad intergeneracional. La creación, entendida como hábitat en cual vivimos, será también cuidada con esmero.', 1),
(9, 'Cuál es el principio de Unicatólica que infiere el cuidado del medio ambiente: ', 'Cuidado de la Casa Común: se reconoce el compromiso de actuar y responder con integridad y respeto en la totalidad de las relaciones e interacciones con los sistemas naturales y sociales, en función de la promoción de la calidad de vida y la solidaridad intergeneracional. La creación, entendida como hábitat en cual vivimos, será también cuidada con esmero.', 'Respeto por la Dignidad Humana: se reconoce a la persona como sujeto con valor en sí mismo y con derechos intrínsecos e inalienables derivados de su condición humana.', 'Vivencia de la Identidad Cristiana-Eclesial: se reconoce la identidad centrada en la formación de seres humanos capaces de realizarse plena e integralmente en su dimensión relacional: consigo mismo, con los demás, con el entorno y con el trascendente.', 'Libertad de Pensamiento y Actitud Crítica: se respetan las distintas ideas, opiniones, creencias y posturas, en el marco no negociable de la dignidad humana; en un ejercicio consciente de actitud crítica, entendida como la capacidad de cuestionarse permanentemente, de expresarse abierta, directa y honestamente, pero respetuosamente frente a las distintas posturas y de valoración de los cuestionamientos del otro.', 1),
(10, 'En los principios de Unicatólica “Respeto por la dignidad humana” refiere a:', 'se reconoce a la persona como sujeto con valor en sí mismo y con derechos intrínsecos e inalienables derivados de su condición humana.', 'se reconoce a la persona como sujeto con poco valor en sí mismo y con derechos intrínsecos e inalienables derivados de su condición humana.', 'se reconoce a la persona como sujeto con valor en sí mismo y con derechos intrínsecos alienables derivados de su condición humana.', 'se reconoce a la persona como sujeto con valor en sociedad, con derechos intrínsecos e inalienables derivados de su condición humana.', 1),
(11, 'En los principios de Unicatólica “Vivencia de la Identidad Cristiana-Eclesial” refiere a:', 'se reconoce la identidad centrada en la formación de seres humanos capaces de realizarse plena e integralmente en su dimensión relacional: consigo mismo, con los demás, con el entorno y con el trascendente.', 'se reconoce la identidad centrada en los seres humanos capaces de realizarse plena e integralmente en su dimensión relacional: consigo mismo, con los demás, con el entorno y con el trascendente.', 'se reconoce la identidad centrada en los seres humanos capaces de realizarse plena en su dimensión relacional: consigo mismo, con los demás, con el entorno y con el trascendente.', 'No se reconoce la identidad centrada en la formación de seres humanos capaces de realizarse plena e integralmente en su dimensión relacional: consigo mismo, con los demás, con el entorno y con el trascendente.', 1),
(12, 'En los principios de Unicatólica “Libertad de Pensamiento y Actitud Crítica” refiere a:', 'se respetan las distintas ideas, opiniones, creencias y posturas, en el marco no negociable de la dignidad humana ', 'se irrespetan las distintas ideas, opiniones, creencias y posturas, en el marco no negociable de la dignidad humana ', 'se respetan las ideas semejantes, opiniones, creencias y posturas, en el marco no negociable de la dignidad humana ', 'se respetan las distintas ideas, opiniones, creencias y posturas, en el marco negociable de la dignidad humana ', 1),
(13, 'En los principios de Unicatólica “Cuidado de la Casa Común” refiere a:', 'se reconoce el compromiso de actuar y responder con integridad y respeto en la totalidad de las relaciones e interacciones con los sistemas naturales y sociales, en función de la promoción de la calidad de vida y la solidaridad intergeneracional. ', 'No se reconoce el compromiso de actuar y responder con integridad y respeto en la totalidad de las relaciones e interacciones con los sistemas naturales y sociales, en función de la promoción de la calidad de vida y la solidaridad intergeneracional. ', 'se reconoce el compromiso de responder en la totalidad de las relaciones e interacciones con los sistemas naturales y sociales, en función de la promoción de la calidad de vida y la solidaridad intergeneracional. ', 'se reconoce el compromiso de actuar y responder con integridad y respeto en la totalidad de las relaciones e interacciones con los sistemas naturales y sociales, en función de la promoción del día y la solidaridad intergeneracional. ', 1),
(14, 'En los principios de Unicatólica “Responsabilidad Social” refiere a:', 'se compromete en la construcción de relaciones responsables y éticas que contribuyan a la transformación de las condiciones sociales, económicas, políticas y culturales, para una sociedad más justa, incluyente, participativa y democrática. ', 'se compromete en la construcción de relaciones sociales y divertidas que contribuyan a la transformación de las condiciones sociales, económicas, políticas y culturales, para una sociedad más justa, incluyente, participativa y democrática. ', 'se compromete en la construcción de relaciones institucionales y sociales que contribuyan a la transformación de las condiciones sociales, económicas, políticas y culturales, para una sociedad más justa, incluyente, participativa y democrática. ', 'se compromete en la deconstrucción de relaciones responsables y éticas que contribuyan a la transformación de las condiciones sociales, económicas, políticas y culturales, para una sociedad más justa, incluyente, participativa y democrática. ', 1),
(15, 'En los principios de Unicatólica “Búsqueda Permanente de la Calidad” refiere a:', 'se reconoce la calidad como el conjunto de condiciones que permiten evaluar, en un tiempo determinado, a la luz de los propósitos institucionales, la coherencia entre la misión y los propósitos institucionales, con sus procesos internos de gestión y los requerimientos sociales de su entorno. ', 'No reconoce la calidad como el conjunto de condiciones que permiten evaluar, en un tiempo determinado, a la luz de los propósitos institucionales, la coherencia entre la misión y los propósitos institucionales, con sus procesos internos de gestión y los requerimientos sociales de su entorno. ', 'se reconoce la calidad como el conjunto de condiciones que permiten evaluar, sin importar el tiempo, a la luz de los propósitos institucionales, la coherencia entre la misión y los propósitos institucionales, con sus procesos internos de gestión y los requerimientos sociales de su entorno. ', 'se reconoce la calidad como el conjunto de condiciones que permiten evaluar, en un tiempo determinado, a la luz de los propósitos institucionales, la incoherencia entre la misión y los propósitos institucionales, con sus procesos internos de gestión y los requerimientos sociales de su entorno. ', 1),
(16, 'En los principios de Unicatólica “Sensibilidad y Solidaridad Social” refiere a:', 'fomentar procesos de organización y participación social, ciudadana y política en la exigibilidad de los derechos humanos y el rechazo a toda forma de vulneración de los mismos.', 'fomentar procesos de desorganización y participación social, ciudadana y política en la exigibilidad de los derechos humanos y el rechazo a toda forma de vulneración de los mismos.', 'fomentar procesos de organización y división social, ciudadana y política en la exigibilidad de los derechos humanos y el rechazo a toda forma de vulneración de los mismos.', 'fomentar procesos de organización y participación social, ciudadana y política en la exigibilidad de los derechos humanos y a toda forma de vulneración de los mismos.', 1),
(17, 'En los principios de Unicatólica “Compromiso con la Paz y la Reconciliación” refiere a:', 'entendida como un conjunto de acciones para la construcción de consensos, que posibiliten acuerdos fundados en el respeto a la vida y la dignidad humana, como derecho fundamental de toda sociedad.', 'entendida como un conjunto de acciones para la deconstrucción de consensos, que posibiliten acuerdos fundados en el respeto a la vida y la dignidad humana, como derecho fundamental de toda sociedad.', 'entendida como un conjunto de acciones para la construcción de disensos, que posibiliten acuerdos fundados en el respeto a la vida y la dignidad humana, como derecho fundamental de toda sociedad.', 'entendida como un conjunto de acciones para la construcción de consensos, que posibiliten desacuerdos fundados en el respeto a la vida y la dignidad humana, como derecho fundamental de toda sociedad.', 1),
(18, 'Los cuatro valores de Unicatólica son:', 'Honestidad, igualdad, equidad y justicia, respeto ', 'Honestidad, desigualdad, equidad y justicia, respeto ', 'Honestidad, igualdad, equidad y justicia, disciplina ', 'Honestidad, igualdad, tranquilidad y justicia, respeto ', 1),
(19, 'En los valores de Unicatólica “Honestidad” refiere a:', 'se reconoce como la actitud, el comportamiento y la expresión sincera y coherente sobre la base de la justicia y la verdad.', 'se reconoce como la aptitud, el comportamiento y la expresión sincera y coherente sobre la base de la justicia y la verdad.', 'se reconoce como la aptitud, el comportamiento y la expresión sincera y incoherente sobre la base de la justicia y la verdad.', 'se reconoce como la actitud, el comportamiento y la expresión sincera y coherente sobre la base de las minorías.', 1),
(20, 'En los valores de Unicatólica “Igualdad” refiere a:', 'se reconoce que todas las personas gozan de los mismos derechos humanos y fundamentales, sin discriminación alguna por razones de sexo, religión, ideas políticas, diferencias culturales, nacionalidad o cualquier otra situación social.', 'se reconoce que todas las personas gozan de diferentes derechos humanos y fundamentales, sin discriminación alguna por razones de sexo, religión, ideas políticas, diferencias culturales, nacionalidad o cualquier otra situación social.', 'se reconoce que todas las personas gozan de los mismos derechos humanos y fundamentales, con discriminación por razones de sexo, religión, ideas políticas, diferencias culturales, nacionalidad o cualquier otra situación social.', 'se reconoce que todas las personas gozan de los mismos derechos humanos y fundamentales, sin discriminación alguna por razones de sexo, religión, ideas políticas, diferencias culturales, nacionalidad excepto por equipo de futbol.', 1),
(21, 'En los valores de Unicatólica “Equidad y Justicia” refiere a:', 'se reconoce como la voluntad de brindar oportunidades con base en criterios objetivos que acojan las necesidades, realidades e intereses de las personas, reconociendo y respetando su contexto social, cultural, político, económico e ideológico.', 'se reconoce como la voluntad de negar oportunidades con base en criterios objetivos que acojan las necesidades, realidades e intereses de las personas, reconociendo y respetando su contexto social, cultural, político, económico e ideológico.', 'se reconoce como la voluntad de brindar oportunidades con base en criterios subjetivos que acojan las necesidades, realidades e intereses de las personas, reconociendo y respetando su contexto social, cultural, político, económico e ideológico.', 'se reconoce como la voluntad de brindar oportunidades con base en criterios objetivos que se desvinculen de las necesidades, realidades e intereses de las personas, reconociendo y respetando su contexto social, cultural, político, económico e ideológico.', 1),
(22, 'En los valores de Unicatólica “Respeto” refiere a:', 'se concibe como el reconocimiento de la autonomía del ser humano y la diferencia, de sus virtudes, derechos y limitaciones, en busca de su desarrollo social e individual.', 'se concibe como el reconocimiento de la dependencia del ser humano y la diferencia, de sus virtudes, derechos y limitaciones, en busca de su desarrollo social e individual.', 'se concibe como el reconocimiento de la dependencia del ser humano y la igualdad, de sus virtudes, derechos y limitaciones, en busca de su desarrollo social e individual.', 'se concibe como el desconocimiento de la autonomía del ser humano y la diferencia, de sus virtudes, derechos y limitaciones, en busca de su desarrollo social e individual.', 1),
(23, 'Los colores que luce la bandera de Unicatólica son:', 'Dorado, azul y blanco', 'Amarillo, azul y blanco', 'Verde, azul y blanco', 'Amarillo y blanco', 1);
